import { describe, it, expect } from 'bun:test';
import {
  isSerene,
  isRuminating,
  metabolicCostPerRound,
  cumulativeMetabolicCost,
  totalLeak,
  hasDisharmony,
  isInternalLoop,
  isExternalThreat,
  classifyKiSignal,
  disruptionLoss,
  disruptionWorstCase,
  minimaxDisruption,
  forkRuminationScenarios,
  kiDisruptRumination,
  convergenceToSerenity,
  evaluatePrinciples,
  diagnoseRumination,
  type CoverSpaceState,
  type KiChannels,
} from './rumination-topology';

// ---------------------------------------------------------------------------
// Part I: The Rumination Model
// ---------------------------------------------------------------------------

describe('CoverSpaceState', () => {
  const sereneState: CoverSpaceState = {
    branches: 1, coherence: 100, rounds: 0, crossings: 0,
  };
  const ruminatingState: CoverSpaceState = {
    branches: 4, coherence: 30, rounds: 10, crossings: 3,
  };

  it('recognizes the Absolute Unknot as serene', () => {
    expect(isSerene(sereneState)).toBe(true);
  });

  it('serene state is not ruminating', () => {
    expect(isRuminating(sereneState, 70)).toBe(false);
  });

  it('recognizes rumination: multiple branches, low coherence, crossings', () => {
    expect(isRuminating(ruminatingState, 70)).toBe(true);
  });

  it('ruminating state is not serene', () => {
    expect(isSerene(ruminatingState)).toBe(false);
  });

  it('serene state has zero metabolic cost', () => {
    expect(metabolicCostPerRound(sereneState)).toBe(0);
  });

  it('rumination has positive metabolic cost per round', () => {
    expect(metabolicCostPerRound(ruminatingState)).toBe(12); // 4 * 3
  });

  it('cumulative cost = rounds * cost/round', () => {
    expect(cumulativeMetabolicCost(ruminatingState)).toBe(120); // 10 * 12
  });

  it('rumination cost is unbounded: for any M, sufficient rounds exceed it', () => {
    const M = 1_000_000;
    const branches = 2;
    const crossings = 1;
    const roundsNeeded = M + 1;
    expect(roundsNeeded * (branches * crossings)).toBeGreaterThan(M);
  });

  it('greedy rejection: after 2 rounds, phantom > spike', () => {
    const spikeCost = 3;
    const phantomPerRound = 2;
    const rounds = 2;
    expect(rounds * phantomPerRound).toBeGreaterThan(spikeCost);
  });
});

// ---------------------------------------------------------------------------
// Part II: Ki Detection
// ---------------------------------------------------------------------------

describe('Ki Detection', () => {
  const internalLoop: KiChannels = {
    glanceLeak: 3, muscleLeak: 0, scentLeak: 0, energyLeak: 5,
  };
  const externalThreat: KiChannels = {
    glanceLeak: 0, muscleLeak: 4, scentLeak: 3, energyLeak: 1,
  };
  const balanced: KiChannels = {
    glanceLeak: 2, muscleLeak: 2, scentLeak: 2, energyLeak: 2,
  };
  const silent: KiChannels = {
    glanceLeak: 0, muscleLeak: 0, scentLeak: 0, energyLeak: 0,
  };

  it('internal loop: high energy + glance, low muscle + scent', () => {
    expect(isInternalLoop(internalLoop)).toBe(true);
    expect(isExternalThreat(internalLoop)).toBe(false);
  });

  it('external threat: high muscle + scent, low energy + glance', () => {
    expect(isExternalThreat(externalThreat)).toBe(true);
    expect(isInternalLoop(externalThreat)).toBe(false);
  });

  it('internal loop and external threat are mutually exclusive', () => {
    for (const k of [internalLoop, externalThreat, balanced, silent]) {
      expect(isInternalLoop(k) && isExternalThreat(k)).toBe(false);
    }
  });

  it('classifies signal patterns correctly', () => {
    expect(classifyKiSignal(internalLoop)).toBe('internal-loop');
    expect(classifyKiSignal(externalThreat)).toBe('external-threat');
    expect(classifyKiSignal(balanced)).toBe('balanced');
  });

  it('internal loop implies disharmony', () => {
    expect(hasDisharmony(internalLoop)).toBe(true);
  });

  it('silence has no disharmony', () => {
    expect(hasDisharmony(silent)).toBe(false);
  });

  it('totalLeak sums all four channels', () => {
    expect(totalLeak(internalLoop)).toBe(8);
    expect(totalLeak(silent)).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Part III: Disruption Strategies
// ---------------------------------------------------------------------------

describe('Disruption Strategies', () => {
  it('accept-spike has uniform cost of 2 across all scenarios', () => {
    expect(disruptionLoss('accept-spike', 'loop-continues')).toBe(2);
    expect(disruptionLoss('accept-spike', 'loop-deepens')).toBe(2);
    expect(disruptionLoss('accept-spike', 'loop-breaks')).toBe(2);
  });

  it('ground worst case = 5', () => {
    expect(disruptionWorstCase('ground')).toBe(5);
  });

  it('redirect worst case = 4', () => {
    expect(disruptionWorstCase('redirect')).toBe(4);
  });

  it('accept-spike worst case = 2', () => {
    expect(disruptionWorstCase('accept-spike')).toBe(2);
  });

  it('accept-spike is minimax optimal', () => {
    expect(minimaxDisruption()).toBe('accept-spike');
  });

  it('every disruption dominates endurance (cost 6)', () => {
    expect(disruptionWorstCase('ground')).toBeLessThan(6);
    expect(disruptionWorstCase('redirect')).toBeLessThan(6);
    expect(disruptionWorstCase('accept-spike')).toBeLessThan(6);
  });
});

// ---------------------------------------------------------------------------
// Part IV: Ki-FRF Controller
// ---------------------------------------------------------------------------

describe('Ki-FRF Disruption Controller', () => {
  const ruminationSignal: KiChannels = {
    glanceLeak: 4, muscleLeak: 1, scentLeak: 0, energyLeak: 6,
  };

  it('internal loop forks pessimistic scenario ordering', () => {
    const scenarios = forkRuminationScenarios(ruminationSignal);
    expect(scenarios[0]).toBe('loop-deepens');
  });

  it('ki controller detects internal loop and selects accept-spike', () => {
    const result = kiDisruptRumination(ruminationSignal);
    expect(result.detected).toBe(true);
    expect(result.signalClass).toBe('internal-loop');
    expect(result.action).toBe('accept-spike');
    expect(result.worstCaseCost).toBe(2);
    expect(result.dominatesEndurance).toBe(true);
    expect(result.dominatesGround).toBe(true);
    expect(result.dominatesRedirect).toBe(true);
  });

  it('balanced signal does not detect rumination', () => {
    const balanced: KiChannels = {
      glanceLeak: 2, muscleLeak: 2, scentLeak: 2, energyLeak: 2,
    };
    const result = kiDisruptRumination(balanced);
    expect(result.detected).toBe(false);
    expect(result.signalClass).toBe('balanced');
    // still selects accept-spike as minimax -- it's optimal regardless
    expect(result.action).toBe('accept-spike');
  });
});

// ---------------------------------------------------------------------------
// Part V: Convergence to Serenity
// ---------------------------------------------------------------------------

describe('Convergence to Serenity', () => {
  it('serene state is already there', () => {
    const path = convergenceToSerenity({
      branches: 1, coherence: 100, rounds: 0, crossings: 0,
    });
    expect(path.alreadySerene).toBe(true);
    expect(path.maxRounds).toBe(0);
    expect(path.sereneCost).toBe(0);
  });

  it('ruminating state has finite convergence path', () => {
    const path = convergenceToSerenity({
      branches: 5, coherence: 20, rounds: 50, crossings: 7,
    });
    expect(path.alreadySerene).toBe(false);
    expect(path.maxRounds).toBe(7); // at most crossings steps
    expect(path.sereneCost).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Part VI: The Four Disruption Principles
// ---------------------------------------------------------------------------

describe('Four Disruption Principles', () => {
  it('validates all four for a ruminating state', () => {
    const p = evaluatePrinciples({
      branches: 3, coherence: 40, rounds: 8, crossings: 2,
    });
    expect(p.notMoralFailure).toBe(true);  // coherence < 100
    expect(p.noExternalSource).toBe(true);  // conservation
    expect(p.notPermanent).toBe(true);      // finite crossings
    expect(p.oneGradient).toBe(true);       // coherence + deficit = 100
  });
});

// ---------------------------------------------------------------------------
// Full Diagnostic
// ---------------------------------------------------------------------------

describe('diagnoseRumination', () => {
  it('produces complete diagnostic for an actively ruminating state', () => {
    const state: CoverSpaceState = {
      branches: 4, coherence: 25, rounds: 12, crossings: 5,
    };
    const ki: KiChannels = {
      glanceLeak: 3, muscleLeak: 0, scentLeak: 1, energyLeak: 7,
    };
    const diag = diagnoseRumination(state, ki);

    expect(diag.isCurrentlyRuminating).toBe(true);
    expect(diag.disruption.detected).toBe(true);
    expect(diag.disruption.action).toBe('accept-spike');
    expect(diag.convergence.maxRounds).toBe(5);
    expect(diag.currentMetabolicCost).toBe(20); // 4 * 5
    expect(diag.cumulativeCost).toBe(240); // 12 * 20
    expect(diag.principles.notMoralFailure).toBe(true);
    expect(diag.principles.notPermanent).toBe(true);
  });
});
